15: GrpcConfigSubscriptionFactory::create(ConfigSubscriptionFactory::SubscriptionData& data) {
16:   GrpcMuxSharedPtr mux;
17:   const envoy::config::core::v3::ApiConfigSource& api_config_source =
18:       data.config_.api_config_source();
19:   CustomConfigValidatorsPtr custom_config_validators = std::make_unique<CustomConfigValidatorsImpl>(
20:       data.validation_visitor_, data.server_, api_config_source.config_validators());
21:   const std::string control_plane_id = Utility::getGrpcControlPlane(api_config_source).value_or("");
22: 
23:   auto strategy_or_error = Utility::prepareJitteredExponentialBackOffStrategy(
24:       api_config_source, data.api_.randomGenerator(), SubscriptionFactory::RetryInitialDelayMs,
25:       SubscriptionFactory::RetryMaxDelayMs);
26:   THROW_IF_NOT_OK_REF(strategy_or_error.status());
27:   JitteredExponentialBackOffStrategyPtr backoff_strategy = std::move(strategy_or_error.value());
28: 
29:   auto factory_primary_or_error = Utility::factoryForGrpcApiConfigSource(
30:       data.cm_.grpcAsyncClientManager(), api_config_source, data.scope_, true, 0, false);
31:   THROW_IF_NOT_OK_REF(factory_primary_or_error.status());
32:   absl::StatusOr<RateLimitSettings> rate_limit_settings_or_error =
33:       Utility::parseRateLimitSettings(api_config_source);
34:   THROW_IF_NOT_OK_REF(rate_limit_settings_or_error.status());
35:   GrpcMuxContext grpc_mux_context{
36:       /*async_client_=*/THROW_OR_RETURN_VALUE(
37:           factory_primary_or_error.value()->createUncachedRawAsyncClient(),
38:           Grpc::RawAsyncClientSharedPtr),
39:       /*failover_async_client_=*/nullptr, // Failover is only supported for ADS.
40:       /*dispatcher_=*/data.dispatcher_,
41:       /*service_method_=*/sotwGrpcMethod(data.type_url_),
42:       /*local_info_=*/data.local_info_,
43:       /*rate_limit_settings_=*/rate_limit_settings_or_error.value(),
44:       /*scope_=*/data.scope_,
45:       /*config_validators_=*/std::move(custom_config_validators),
46:       /*xds_resources_delegate_=*/data.xds_resources_delegate_,
47:       /*xds_config_tracker_=*/data.xds_config_tracker_,
48:       /*backoff_strategy_=*/std::move(backoff_strategy),
49:       /*target_xds_authority_=*/control_plane_id,
50:       /*eds_resources_cache_=*/nullptr, // EDS cache is only used for ADS.
51:       /*skip_subsequent_node_=*/api_config_source.set_node_on_first_message_only()};
52: 
53:   if (Runtime::runtimeFeatureEnabled("envoy.reloadable_features.unified_mux")) {
54:     mux = std::make_shared<Config::XdsMux::GrpcMuxSotw>(grpc_mux_context);
55:   } else {
56:     mux = std::make_shared<Config::GrpcMuxImpl>(grpc_mux_context);
57:   }
58:   return std::make_unique<GrpcSubscriptionImpl>(
59:       std::move(mux), data.callbacks_, data.resource_decoder_, data.stats_, data.type_url_,
60:       data.dispatcher_, Utility::configSourceInitialFetchTimeout(data.config_),
61:       /*is_aggregated*/ false, data.options_);
62: }
